import React from 'react'

export default function (props: any) {
    console.log(props);
    const node = props.acitveNode;
    const nodeData = props.activeNode.data;
    const formData = nodeData.formData;

    return (
        <div>
            <h1>
                {nodeData.name}
            </h1>
            <h2>
                Parameters
            </h2>
            <form>
                {
                    formData.map((param: any) => {
                        return (
                            <div>
                                <label>
                                    {param.name}
                                </label>
                                <input type="text" value={param.value} onChange={(e) => {
                                    param.value = e.target.value;
                                }} />
                            </div>
                        )
                    })
                }
                <div>
                    <label>
                        Additional Instructions
                    </label>
                    <textarea defaultValue={nodeData.additionalInstructions} onChange={(e) => {
                        nodeData.additionalInstructions = e.target.value;
                    }} />
                </div>
            </form>
        </div>
    )
}
